#include <bits/stdc++.h>using namespace std;#define int long long int#define all(x) x.begin(), x.end()const int mod = 998244353; pair<int, int> yo(int k) {    int x, y;    if (k < 0) x = 0;    else {        if (k >= 3) x = 2 + (k - 3) / 4;        else x = 1;    }      if (k < 1) y = 0;    else y = (k - 1) / 4 + 1;    return {x, y};}void solve() {    int n, x; cin >> n >> x;    auto [gua, mara] = yo (n);    auto [GUA, MARA] = yo (x - 1);    cout << ((GUA % mod * ((gua - GUA) % mod)) + (MARA % mod * ((mara - MARA) % mod))) % mod << '\n';}int32_t main() {    ios_base::sync_with_stdio(0); cin.tie(0);    int t = 1; cin >> t;    while (t--) solve();    return 0;}